                       <div className="absolute inset-0 bg-gradient-to-t from-[#250f0b] to-transparent"></div>
                       <div className="absolute bottom-4 left-4 flex items-center gap-3">
                          <div className="w-8 h-8 bg-[#cb9651] animate-spin"></div>
                          <span className="pixel-font text-2xl text-[#e4c388] drop-shadow-[2px_2px_0px_#250f0b]">GULCH_SECTOR_3</span>
                       </div>
                    </div>
                    <BorderedCard title="FRONTIER_WHISPERS">
                       <p className="typewriter-font text-xs text-[#e4c388]/60 italic leading-relaxed border-l-4 border-[#cb9651] pl-3 py-1">
                         "THE RATTLESNAKE GANG WAS SEEN SHEDDING SKINS NEAR THE CREEK. KEEP YOUR CLAWS READY."
                       </p>
                    </BorderedCard>
                  </div>
               </div>
            </div>
          )}

          {currentScene === 'HighNoon' && (
            <div className="flex flex-col items-center justify-center min-h-[600px] border-[16px] border-[#663219] bg-[#250f0b] relative overflow-hidden shadow-[inset_0_0_100px_rgba(0,0,0,1)]">
               <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/old-map.png')] opacity-10"></div>

               <div className="relative z-10 text-center mb-16">
                  <h2 className="pixel-font text-9xl text-[#cb9651] animate-bounce drop-shadow-[10px_10px_0px_#250f0b]">DRAW!</h2>
                  <div className="h-1 w-64 bg-[#cb9651] mx-auto mt-2 animate-pulse"></div>
                  <p className="pixel-font text-xl text-[#e4c388] mt-4 tracking-[0.8em] opacity-80">HIGH_NOON_DUEL</p>
               </div>

               <div className="flex flex-col md:flex-row items-center space-y-16 md:space-y-0 md:space-x-40 relative z-10">
                  <div className="flex flex-col items-center">
                     <div className="w-48 h-48 border-8 border-[#cb9651] bg-[#250f0b] p-4 shadow-[12px_12px_0px_#663219]">
                        <img src="https://api.dicebear.com/7.x/pixel-art/svg?seed=buck-thompson&backgroundColor=transparent" alt="Hero" className="w-full h-full object-contain brightness-90 contrast-110" />
                     </div>
                     <span className="pixel-font text-3xl mt-6 text-[#cb9651] tracking-tighter">{character.name}</span>
                     <div className="mt-2 text-[10px] pixel-font text-[#e4c388]">INSTINCT_LVL: {totalStats.aim + totalStats.reflexes}</div>
