                  <div className="pixel-font text-[120px] text-[#cb9651]/5 absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none select-none">BATTLE</div>

                  <div className="flex flex-col items-center">
                     <div className="w-48 h-48 border-8 border-red-700 bg-[#250f0b] p-4 shadow-[12px_12px_0px_#250f0b]">
                        <img src="https://api.dicebear.com/7.x/pixel-art/svg?seed=slick-pete-rattlesnake&backgroundColor=transparent" alt="Boss" className="w-full h-full object-contain grayscale brightness-50 contrast-150" />
                     </div>
                     <span className="pixel-font text-3xl mt-6 text-red-700 tracking-tighter">SLICK_PETE</span>
                     <div className="mt-2 text-[10px] pixel-font text-red-700">DANGER_LVL: HIGH</div>
                  </div>
               </div>

               <WesternButton 
                 variant="primary" 
                 className="mt-24 text-5xl px-24 py-10 shadow-[8px_8px_0px_#250f0b]"
