                <p className="typewriter-font text-sm leading-relaxed italic">"THE {currentScene.toUpperCase()} HAS GONE INTO HIBERNATION. CHECK BACK AFTER THE NEXT MOON CYCLE."</p>
              </div>
              <WesternButton variant="accent" className="mt-12" onClick={() => setCurrentScene('Character')}>BACK_TO_DEN</WesternButton>
            </div>
          )}
        </div>
      </main>
    </div>
