};

const EquipSlot: React.FC<{ slot: Slot, item: Item | null, onUnequip: () => void }> = ({ slot, item, onUnequip }) => {
  const content = (
    <div 
      className={`w-full h-full border-4 flex flex-col items-center justify-center relative transition-all cursor-default shadow-[4px_4px_0px_#250f0b] ${
        item ? 'bg-[#663219] border-[#cb9651]' : 'bg-[#250f0b] border-[#663219] opacity-40'
      }`}
    >
      {!item && <span className="text-[7px] pixel-font font-black text-[#e4c388] text-center p-1 leading-none">{slot}</span>}
      {item && (
        <>
          <span className="text-[7px] leading-none text-white font-bold pixel-font uppercase p-1 text-center line-clamp-3">{item.name}</span>
          <button 
            onClick={(e) => { e.stopPropagation(); onUnequip(); }}
            className="absolute -top-3 -right-3 bg-red-700 text-white w-6 h-6 text-[12px] flex items-center justify-center border-2 border-white hover:bg-red-500 pixel-font font-bold"
          >
            X
          </button>
        </>
      )}
    </div>
  );

  return item ? <ItemTooltip item={item}>{content}</ItemTooltip> : content;
};

const InventorySlot: React.FC<{ item: Item | null, isSelected: boolean, onClick: () => void }> = ({ item, isSelected, onClick }) => {
