      </nav>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-10 relative">
        <div className="absolute top-0 left-0 w-full h-24 bg-gradient-to-b from-slate-900 to-transparent opacity-80 pointer-events-none"></div>

        {/* Narrative / Battle Log */}
        {(lastNarrative || isLoadingNarrative) && (
          <div className="mb-10 animate-in slide-in-from-top-4 duration-300 max-w-5xl mx-auto">
            <div className="bg-slate-900/90 border-l-4 border-cyan-500 p-6 relative shadow-[0_0_30px_rgba(0,0,0,0.5)] tech-border">
               <div className="absolute -top-3 left-4 bg-cyan-600 text-white text-[10px] px-2 py-0.5 anime-title font-bold uppercase tracking-widest">
                 System Notification
               </div>
               <h3 className="anime-title text-2xl text-white mb-2 flex items-center gap-2">
                 <Radio className="text-pink-500 animate-pulse" size={20} />
                 INCOMING_TRANSMISSION
               </h3>
               <div className="bg-black/40 p-4 border border-slate-700 rounded text-cyan-100">
                 <p className="anime-text text-lg leading-relaxed">
                   {isLoadingNarrative ? <span className="animate-pulse">DECODING DATA STREAM...</span> : `"${lastNarrative}"`}
