const EquipSlot: React.FC<{ slot: Slot, item: Item | null, onUnequip: () => void }> = ({ slot, item, onUnequip }) => {
  const content = (
    <div 
      className={`w-full h-full border flex flex-col items-center justify-center relative transition-all cursor-default ${
        item ? 'bg-slate-800 border-cyan-500 shadow-[0_0_15px_rgba(0,243,255,0.2)]' : 'bg-slate-900/50 border-slate-700 opacity-50'
      }`}
    >
      {!item && <span className="text-[9px] anime-title text-slate-600 text-center p-1 leading-none tracking-widest">{slot}</span>}
      {item && (
        <>
          <span className="text-[8px] leading-tight text-cyan-100 font-bold anime-title uppercase p-1 text-center line-clamp-2">{item.name}</span>
          <button 
            onClick={(e) => { e.stopPropagation(); onUnequip(); }}
            className="absolute -top-2 -right-2 bg-red-600 text-white w-5 h-5 text-[10px] flex items-center justify-center hover:bg-red-500 rounded-full shadow-lg"
          >
            ×
          </button>
        </>
      )}
    </div>
  );

  return item ? <ItemTooltip item={item}>{content}</ItemTooltip> : content;
};

const InventorySlot: React.FC<{ item: Item | null, isSelected: boolean, onClick: () => void }> = ({ item, isSelected, onClick }) => {
  const content = (
    <div 
      onClick={onClick}
      className={`aspect-square border relative cursor-pointer flex flex-col items-center justify-center transition-all ${
        isSelected 
        ? 'border-cyan-400 bg-cyan-900/30 shadow-[0_0_15px_rgba(0,243,255,0.4)] scale-105 z-10' 
        : 'border-slate-700 bg-slate-900/50 hover:border-slate-500'
      }`}
    >
      {item ? (
        <>
          <span className="text-[7px] anime-title font-bold mt-1 uppercase text-slate-500">{item.slot}</span>
          <div className="p-1 text-center">
            <span className="text-[9px] leading-none text-white anime-title uppercase font-bold">{item.name}</span>
          </div>
        </>
      ) : (
        <div className="opacity-20"><Package size={16} className="text-slate-500" /></div>
      )}
    </div>
  );

  return item ? <ItemTooltip item={item}>{content}</ItemTooltip> : content;
};

