                    ></div>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        <div className="max-w-7xl mx-auto">
          {currentScene === 'Character' && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              {/* Profile / Paperdoll */}
              <div className="flex flex-col">
                <div className="flex items-center gap-4 mb-8">
