            finalIndices.push(i);
            needed--;
            if (needed === 0) break;
          }
        }
      }
      finalIndices.forEach(idx => newInv[idx] = null);

      // Add result
      const targetIdx = newInv.findIndex(i => i === null);
      newInv[targetIdx] = selectedRecipe.result;

      return { ...prev, inventory: newInv };
    });

