    const story = await generateDuelNarrative(
      character.name, 
      character.species, 
      "Viper-X", 
      "Android Assassin", 
      win ? 'Win' : 'Loss'
    );

    addLog(story, 'combat');
    setIsLoadingNarrative(false);

    if (win) {
      addLog(`Target neutralized. Victory rewards: +250¥ | +150XP`, 'reward');
      setCharacter(prev => ({ ...prev, gold: prev.gold + 250, exp: prev.exp + 150 }));
    } else {
      addLog(`Critical damage sustained. Retreating to repair.`, 'combat');
    }
  };

  const handleCraft = () => {
    if (!selectedRecipe) return;

    // Check inventory
    const neededIndices: number[] = [];
    let canCraft = true;

    // Create a copy to track consumption without modifying real inventory yet
    const tempInventory = [...character.inventory];

    for (const ing of selectedRecipe.ingredients) {
      let needed = ing.count;
      for (let i = 0; i < tempInventory.length; i++) {
        if (tempInventory[i]?.id === ing.itemId) {
          neededIndices.push(i);
          tempInventory[i] = null; // Mark as used
          needed--;
          if (needed === 0) break;
        }
      }
      if (needed > 0) {
        canCraft = false;
        break;
      }
    }

    if (!canCraft) {
      addLog(`Fabrication failed: Insufficient materials for ${selectedRecipe.name}.`, 'system');
      return;
    }

    // Check space
    const emptySlotIdx = character.inventory.findIndex(i => i === null);

    if (emptySlotIdx === -1 && tempInventory.findIndex(i => i === null) === -1) {
       addLog(`Fabrication failed: Output bay full. Clear inventory space.`, 'system');
       return;
    }

    // Execute craft
    setCharacter(prev => {
      const newInv = [...prev.inventory];
      // Consume items properly using indices
      const indicesToConsume: number[] = [];
      const consumedMap: Record<string, number> = {};

      // First pass: identify indices
      selectedRecipe.ingredients.forEach(ing => {
         let needed = ing.count;
         for(let i=0; i<newInv.length; i++) {
            if (newInv[i]?.id === ing.itemId && !indicesToConsume.includes(i) && needed > 0) {
               indicesToConsume.push(i);
               needed--;
            }
         }
      });

      // Second pass: remove
      indicesToConsume.forEach(idx => newInv[idx] = null);

      // Third pass: add result
      const targetIdx = newInv.findIndex(i => i === null);
      if (targetIdx !== -1) {
         // Create a unique ID for the new item to ensure animation triggers
         newInv[targetIdx] = { ...selectedRecipe.result, id: selectedRecipe.result.id + '-' + Date.now() };
      }

      return { ...prev, inventory: newInv };
    });

    addLog(`Fabrication complete: Constructed ${selectedRecipe.result.name}.`, 'craft');
  };

