export const ItemTooltip: React.FC<{ item: Item, children: React.ReactNode }> = ({ item, children }) => {
  const rarityConfig = {
    [ItemRarity.Common]: { color: 'text-slate-400', border: 'border-slate-500' },
    [ItemRarity.Uncommon]: { color: 'text-green-400', border: 'border-green-500' },
    [ItemRarity.Rare]: { color: 'text-cyan-400', border: 'border-cyan-500' },
    [ItemRarity.Epic]: { color: 'text-purple-400', border: 'border-purple-500' },
    [ItemRarity.Legendary]: { color: 'text-yellow-400', border: 'border-yellow-500' }
  };

  const config = rarityConfig[item.rarity];

  return (
    <div className="tooltip-trigger relative w-full h-full flex">
      {children}
      <div className="custom-tooltip w-64 pointer-events-none">
        <div className={`bg-slate-950 border ${config.border} shadow-[0_0_30px_rgba(0,0,0,0.8)] overflow-hidden rounded-sm`}>
          <div className={`p-2 bg-slate-900/50 font-bold anime-title text-sm tracking-wide ${config.color}`}>
            {item.name}
          </div>
          <div className="p-3">
            <div className="flex justify-between text-[10px] font-bold mb-2 anime-title text-slate-500">
              <span className="bg-slate-800 px-1 rounded">{item.slot}</span>
              <span className={config.color}>{item.rarity}</span>
            </div>
            <p className="text-xs text-slate-300 mb-3 anime-text leading-tight opacity-90">{item.description}</p>
            {Object.keys(item.stats).length > 0 && (
              <div className="space-y-1 bg-slate-900/50 p-2 rounded border border-white/5">
                {Object.entries(item.stats).map(([stat, val]) => (
                  <div key={stat} className="flex justify-between items-center text-[10px] font-bold anime-title">
                    <span className="text-slate-500 uppercase">{stat}</span>
                    <span className="text-cyan-300">+{val}</span>
                  </div>
                ))}
              </div>
            )}
            <div className="mt-3 flex justify-between items-center">
               <div className="text-[9px] font-mono text-slate-600">UUID:{item.id.slice(0,5)}</div>
               <div className="text-[10px] font-bold text-yellow-500 bg-yellow-500/10 px-2 py-0.5 rounded">¥{item.price}</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

// --- Item Visual Logic ---

const getRarityStyles = (rarity?: ItemRarity) => {
  switch (rarity) {
    case ItemRarity.Legendary:
      return {
        container: "border-yellow-500/70 bg-yellow-900/20 rarity-legendary-glow",
        text: "text-yellow-400 drop-shadow-[0_0_5px_rgba(234,179,8,0.5)]",
        glow: "shadow-[0_0_15px_rgba(234,179,8,0.4)]",
        indicator: "bg-yellow-500",
        particles: true
      };
    case ItemRarity.Epic:
      return {
        container: "border-purple-500/70 bg-purple-900/20 rarity-epic-glow",
        text: "text-purple-400 drop-shadow-[0_0_5px_rgba(168,85,247,0.5)]",
        glow: "shadow-[0_0_10px_rgba(168,85,247,0.3)]",
        indicator: "bg-purple-500",
        particles: false
      };
    case ItemRarity.Rare:
      return {
        container: "border-cyan-500/60 bg-cyan-900/20",
        text: "text-cyan-400 drop-shadow-[0_0_3px_rgba(34,211,238,0.5)]",
        glow: "shadow-[0_0_8px_rgba(34,211,238,0.2)]",
        indicator: "bg-cyan-400",
        particles: false
      };
    case ItemRarity.Uncommon:
      return {
        container: "border-green-500/50 bg-green-900/10",
        text: "text-green-400",
        glow: "shadow-[0_0_5px_rgba(74,222,128,0.1)]",
        indicator: "bg-green-500",
        particles: false
      };
    default: // Common or null
      return {
        container: "border-slate-700 bg-slate-900/50",
        text: "text-slate-400",
        glow: "",
        indicator: "bg-slate-600",
        particles: false
      };
  }
};

export const EquipSlot: React.FC<{ slot: Slot, item: Item | null, onUnequip: () => void }> = ({ slot, item, onUnequip }) => {
  const styles = getRarityStyles(item?.rarity);

  const content = (
    <div 
      className={`w-full h-full border flex flex-col items-center justify-center relative transition-all duration-300 overflow-hidden group 
        ${item ? `${styles.container} ${styles.glow} animate-pop-in` : 'bg-slate-900/50 border-slate-700 opacity-50'}
      `}
    >
      {/* Visual Effects for Legendary/Epic */}
      {item && (item.rarity === ItemRarity.Legendary || item.rarity === ItemRarity.Epic) && (
         <div className="absolute inset-0 animate-holo pointer-events-none opacity-30"></div>
      )}
      {styles.particles && (
         <>
            <div className="absolute top-1/4 left-1/4 w-1 h-1 bg-yellow-200 rounded-full animate-sparkle-1"></div>
            <div className="absolute bottom-1/3 right-1/4 w-0.5 h-0.5 bg-yellow-400 rounded-full animate-sparkle-2"></div>
         </>
      )}

      {!item && <span className="text-[9px] anime-title text-slate-600 text-center p-1 leading-none tracking-widest">{slot}</span>}
      {item && (
        <>
          <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent pointer-events-none"></div>
          <span className={`text-[8px] leading-tight font-bold anime-title uppercase p-1 text-center line-clamp-2 relative z-10 ${styles.text}`}>{item.name}</span>
          <button 
            onClick={(e) => { e.stopPropagation(); onUnequip(); }}
            className="absolute -top-2 -right-2 bg-red-600 text-white w-5 h-5 text-[10px] flex items-center justify-center hover:bg-red-500 rounded-full shadow-lg z-20 cursor-pointer"
          >
            ×
          </button>
        </>
      )}
    </div>
  );

  return item ? <ItemTooltip item={item}>{content}</ItemTooltip> : content;
};

export const InventorySlot: React.FC<{ item: Item | null, isSelected?: boolean, onClick: () => void }> = ({ item, isSelected = false, onClick }) => {
  const styles = getRarityStyles(item?.rarity);

  const content = (
    <div 
      onClick={onClick}
      className={`aspect-square border relative cursor-pointer flex flex-col items-center justify-center transition-all duration-300 overflow-hidden group 
        ${isSelected 
          ? 'border-cyan-400 bg-cyan-900/40 shadow-[0_0_20px_rgba(0,243,255,0.6)] scale-105 z-10 ring-1 ring-cyan-300' 
          : `${styles.container} hover:border-white/30 hover:bg-slate-800`
        } 
        ${item ? 'animate-pop-in' : ''}
      `}
    >
      {/* Background/Holo Effects */}
      {item && (
         <div className={`absolute inset-0 opacity-20 bg-gradient-to-br ${
            item.rarity === 'Legendary' ? 'from-yellow-500 to-transparent' :
            item.rarity === 'Epic' ? 'from-purple-500 to-transparent' :
            item.rarity === 'Rare' ? 'from-cyan-500 to-transparent' :
            'from-white to-transparent'
         }`}></div>
      )}

      {/* Selection scanline */}
      {isSelected && (
        <div className="absolute inset-0 bg-cyan-400/10 animate-pulse pointer-events-none"></div>
      )}

      {/* Particles for High Tier */}
      {styles.particles && !isSelected && (
         <div className="absolute inset-0 pointer-events-none overflow-hidden">
             <div className="absolute top-2 right-2 w-0.5 h-0.5 bg-yellow-100 animate-sparkle-1"></div>
         </div>
      )}

      {item ? (
        <>
          <span className={`text-[7px] anime-title font-bold mt-1 uppercase z-10 ${styles.text}`}>{item.slot}</span>
          <div className="p-1 text-center z-10 relative">
             {/* Icon for Legendary */}
            {item.rarity === ItemRarity.Legendary && <Sparkles size={8} className="mx-auto mb-1 text-yellow-300 animate-pulse" />}
            <span className={`text-[9px] leading-none anime-title uppercase font-bold drop-shadow-md text-white`}>{item.name}</span>
          </div>
        </>
      ) : (
        <div className="opacity-20 group-hover:opacity-40 transition-opacity"><Package size={16} className="text-slate-500" /></div>
      )}
    </div>
  );

  return item ? <ItemTooltip item={item}>{content}</ItemTooltip> : content;
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Character, Item, Scene, Slot, Quest, Recipe, LogEntry, LogType, ItemRarity } from './types';
import { INITIAL_ITEMS, QUESTS } from './constants';
import { WesternButton, BorderedCard, StatsBar, EquipSlot, InventorySlot } from './components/UI';
import { SaloonScene } from './components/scenes/SaloonScene';
import { GuildScene } from './components/scenes/GuildScene';
import { ArenaScene } from './components/scenes/ArenaScene';
import { SynthForgeScene } from './components/scenes/SynthForgeScene';
import { generateQuestNarrative, generateDuelNarrative } from './services/geminiService';
import { User, Trophy, Activity, Sword, Target, Hammer, Terminal, ChevronRight, Radio } from 'lucide-react';

const GRID_SIZE = 20;

const App: React.FC = () => {
  // --- State Management ---
  const [character, setCharacter] = useState<Character>({
    name: 'Kaito "Star-Shot"',
    species: 'Cyborg Human',
    level: 1,
    exp: 0,
    gold: 500,
    baseStats: { aim: 15, reflexes: 12, grit: 10, charisma: 8, stamina: 12 },
    equipment: { Hat: null, Revolver: null, Rifle: null, Poncho: null, Boots: null, Badge: null, Belt: null, Material: null },
    inventory: Array(GRID_SIZE).fill(null).map((_, i) => INITIAL_ITEMS[i] || null)
  });

  const [currentScene, setCurrentScene] = useState<Scene>('Character');
  const [activeQuest, setActiveQuest] = useState<{ quest: Quest; timeRemaining: number; startTime: number } | null>(null);
  const [logs, setLogs] = useState<LogEntry[]>([
    { id: 'init', timestamp: new Date().toLocaleTimeString('en-US', { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" }), message: "System initialized. Welcome, Hunter.", type: 'system' }
  ]);
  const [isLoadingNarrative, setIsLoadingNarrative] = useState(false);
  const [selectedInventoryIdx, setSelectedInventoryIdx] = useState<number | null>(null);
  const [selectedRecipe, setSelectedRecipe] = useState<Recipe | null>(null);

  const logEndRef = useRef<HTMLDivElement>(null);

  // --- Derived State ---
  const totalStats = useMemo(() => {
    const stats = { ...character.baseStats };
    (Object.values(character.equipment) as (Item | null)[]).forEach(item => {
      if (item?.stats) {
        Object.entries(item.stats).forEach(([stat, val]) => {
          if (typeof val === 'number') (stats as any)[stat] += val;
        });
      }
    });
    return stats;
  }, [character]);

  // --- Effects ---
  useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [logs, isLoadingNarrative]);

  useEffect(() => {
    if (!activeQuest) return;
    const timer = setInterval(() => {
      setActiveQuest(prev => {
        if (!prev) return null;
        const remaining = Math.max(0, prev.quest.duration - Math.floor((Date.now() - prev.startTime) / 1000));
        if (remaining === 0) {
          completeQuest(prev.quest);
          return null;
        }
        return { ...prev, timeRemaining: remaining };
      });
    }, 1000);
    return () => clearInterval(timer);
  }, [activeQuest]);

  // --- Actions ---
  const addLog = (message: string, type: LogType = 'system') => {
    const now = new Date();
    const timestamp = now.toLocaleTimeString('en-US', { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" });
    setLogs(prev => {
      const newLogs = [...prev, { id: Math.random().toString(36).substring(2, 9), timestamp, message, type }];
      return newLogs.slice(-100); 
    });
  };

  const completeQuest = async (quest: Quest) => {
    setIsLoadingNarrative(true);
    addLog(`Objective "${quest.title}" phase complete. Uploading mission data...`, 'quest');

    try {
      const story = await generateQuestNarrative(quest.title, character.name, character.species);
      addLog(story, 'quest');
      addLog(`Mission Rewards Processed: +${quest.reward.gold}¥ | +${quest.reward.exp}XP`, 'reward');

      setCharacter(prev => ({ 
        ...prev, 
        gold: prev.gold + quest.reward.gold, 
        exp: prev.exp + quest.reward.exp, 
        level: Math.floor((prev.exp + quest.reward.exp) / 1000) + 1 
      }));
    } catch (e) {
      addLog("Mission data corrupted during upload.", 'system');
    } finally {
      setIsLoadingNarrative(false);
    }
  };

  const handleEquip = (idx: number) => {
    const item = character.inventory[idx];
    if (!item) return;
    if (item.slot === 'Material') {
      addLog(`Cannot equip raw materials. Use them at the Synth-Forge.`, 'system');
      return;
    }
    const slot = item.slot;
    const currentEquipped = character.equipment[slot];
    setCharacter(prev => {
      const newInventory = [...prev.inventory];
      newInventory[idx] = currentEquipped;
      return { ...prev, equipment: { ...prev.equipment, [slot]: item }, inventory: newInventory };
    });
    addLog(`Equipped ${item.name} to ${slot} slot.`, 'system');
    setSelectedInventoryIdx(null);
  };

  const handleUnequip = (slot: Slot) => {
    const item = character.equipment[slot];
    if (!item) return;
    setCharacter(prev => {
      const emptyIdx = prev.inventory.findIndex(i => i === null);
      if (emptyIdx === -1) {
        addLog("Inventory full. Cannot unequip.", 'system');
        return prev;
      }
      const newInventory = [...prev.inventory];
      newInventory[emptyIdx] = item;
      return { ...prev, equipment: { ...prev.equipment, [slot]: null }, inventory: newInventory };
    });
    addLog(`Unequipped ${item.name}.`, 'system');
  };

  const startQuest = (quest: Quest) => {
    if (activeQuest) return;
    setActiveQuest({ quest, timeRemaining: quest.duration, startTime: Date.now() });
    addLog(`Accepted contract: ${quest.title}. Deploying to sector...`, 'quest');
  };

  const runDuel = async () => {
    const win = (totalStats.aim + totalStats.reflexes + Math.random() * 20) > 40;

    addLog(`Combat sequence initiated against Viper-X.`, 'combat');
    addLog(`Analyzing opponent combat patterns...`, 'system');

    setIsLoadingNarrative(true);
    try {
      const story = await generateDuelNarrative(
        character.name, 
        character.species, 
        "Viper-X", 
        "Android Assassin", 
        win ? 'Win' : 'Loss'
      );

      addLog(story, 'combat');
      if (win) {
        addLog(`Target neutralized. Victory rewards: +250¥ | +150XP`, 'reward');
        setCharacter(prev => ({ ...prev, gold: prev.gold + 250, exp: prev.exp + 150 }));
      } else {
        addLog(`Critical damage sustained. Retreating to repair.`, 'combat');
      }
    } catch(e) {
      addLog("Combat log corrupted.", 'system');
    } finally {
      setIsLoadingNarrative(false);
    }
  };

  const handleCraft = () => {
    if (!selectedRecipe) return;

    const tempInventory = [...character.inventory];
    const indicesToConsume: number[] = [];
    let canCraft = true;

    // Check availability
    selectedRecipe.ingredients.forEach(ing => {
      let needed = ing.count;
      for (let i = 0; i < tempInventory.length; i++) {
        if (tempInventory[i]?.id === ing.itemId && !indicesToConsume.includes(i) && needed > 0) {
          indicesToConsume.push(i);
          needed--;
        }
      }
      if (needed > 0) canCraft = false;
    });

    if (!canCraft) {
      addLog(`Fabrication failed: Insufficient materials for ${selectedRecipe.name}.`, 'system');
      return;
    }

    const freeSlots = tempInventory.filter((item, idx) => item === null || indicesToConsume.includes(idx)).length;
    if (freeSlots === 0) {
       addLog(`Fabrication failed: Output bay full. Clear inventory space.`, 'system');
       return;
    }

    setCharacter(prev => {
      const newInv = [...prev.inventory];
      indicesToConsume.forEach(idx => newInv[idx] = null);

      const targetIdx = newInv.findIndex(i => i === null);
      if (targetIdx !== -1) {
         newInv[targetIdx] = { ...selectedRecipe.result, id: selectedRecipe.result.id + '-' + Date.now() };
      }
      return { ...prev, inventory: newInv };
    });

    addLog(`Fabrication complete: Constructed ${selectedRecipe.result.name}.`, 'craft');
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row relative z-10 scanline">
      {/* Sidebar Navigation */}
      <nav className="w-full md:w-72 bg-slate-900/90 border-r border-cyan-500/20 flex flex-col p-6 z-20 backdrop-blur-md">
        <div className="mb-10 text-center group">
          <div className="relative inline-block">
             <div className="absolute inset-0 bg-cyan-500/20 skew-x-12 -z-10 blur-xl"></div>
             <h1 className="anime-title text-5xl text-white italic font-black drop-shadow-[0_0_10px_rgba(0,243,255,0.8)] tracking-tighter">
              NEON<br/><span className="text-cyan-400">FRONTIER</span>
            </h1>
          </div>
          <div className="text-[10px] anime-title text-pink-500 mt-2 tracking-[0.3em] font-bold">SPACE_BOUNTY_RPG_V1.0</div>
        </div>

        <div className="space-y-3">
          {[
            { id: 'Character', icon: User, label: 'DASHBOARD' },
            { id: 'Saloon', icon: Activity, label: 'HUB' },
            { id: 'Sheriff', icon: Target, label: 'GUILD' },
            { id: 'Gunsmith', icon: Hammer, label: 'SYNTH-FORGE' },
            { id: 'HighNoon', icon: Sword, label: 'ARENA' }
          ].map(item => (
            <button
              key={item.id}
              onClick={() => setCurrentScene(item.id as Scene)}
              className={`w-full flex items-center justify-between p-3 anime-title text-lg transition-all border-l-4 ${
                currentScene === item.id 
                ? 'bg-gradient-to-r from-cyan-900/50 to-transparent border-cyan-400 text-cyan-300 translate-x-2' 
                : 'border-transparent text-slate-500 hover:text-white hover:border-pink-500 hover:bg-white/5'
              }`}
            >
              <span className="flex items-center gap-3">
                <item.icon size={18} />
                {item.label}
              </span>
              {currentScene === item.id && <ChevronRight size={16} className="animate-pulse" />}
            </button>
          ))}
        </div>

        <div className="mt-auto pt-6 border-t border-slate-700">
          <div className="flex justify-between items-center mb-4 text-cyan-400">
            <div className="flex flex-col items-center">
              <span className="text-[9px] anime-title text-slate-400">CREDITS</span>
              <div className="flex items-center space-x-1">
                <span className="anime-title font-bold text-xl">¥{character.gold}</span>
              </div>
            </div>
            <div className="flex flex-col items-center">
              <span className="text-[9px] anime-title text-slate-400">RANK</span>
              <div className="flex items-center space-x-1">
                <Trophy size={14} className="text-pink-500" />
                <span className="anime-title font-bold text-xl">{character.level}</span>
              </div>
            </div>
          </div>
          <StatsBar label="REP_LEVEL" value={character.exp % 1000} max={1000} color="from-pink-500 to-purple-600" />
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-10 relative">
        <div className="absolute top-0 left-0 w-full h-24 bg-gradient-to-b from-slate-900 to-transparent opacity-80 pointer-events-none"></div>

        {/* Console Log */}
        <div className="mb-10 max-w-6xl mx-auto">
          <div className="bg-slate-950/95 border border-cyan-500/30 tech-border flex flex-col shadow-[0_0_40px_rgba(0,0,0,0.6)] rounded-lg overflow-hidden">

             <div className="bg-slate-900 p-2 px-4 border-b border-cyan-500/20 flex justify-between items-center">
                <div className="flex items-center gap-2">
                   <Terminal size={16} className="text-cyan-400" />
                   <span className="anime-title text-xs text-cyan-100 tracking-widest">SYSTEM_CONSOLE_LOG // V.2.4.1</span>
                </div>
                <div className="flex gap-2">
                   <div className="w-3 h-3 bg-red-500/20 rounded-full border border-red-500/50"></div>
                   <div className="w-3 h-3 bg-yellow-500/20 rounded-full border border-yellow-500/50"></div>
                   <div className="w-3 h-3 bg-green-500/20 rounded-full border border-green-500/50"></div>
                </div>
             </div>

             <div className="h-48 overflow-y-auto p-4 font-mono text-sm bg-black/80 space-y-2 relative custom-scrollbar">
                {logs.length === 0 && <div className="text-slate-600 italic">No activity recorded...</div>}

                {logs.map((log) => (
                   <div key={log.id} className="flex gap-3 animate-in fade-in duration-300">
                      <span className="text-slate-600 select-none">[{log.timestamp}]</span>
                      <span className={`
                         ${log.type === 'system' ? 'text-slate-400' : ''}
                         ${log.type === 'combat' ? 'text-red-400' : ''}
                         ${log.type === 'quest' ? 'text-cyan-400' : ''}
                         ${log.type === 'reward' ? 'text-yellow-400 font-bold' : ''}
                         ${log.type === 'craft' ? 'text-orange-400 font-bold' : ''}
                      `}>
                         {log.type === 'system' && <span className="mr-2 text-slate-600">{'>'}</span>}
                         {log.type === 'combat' && <Sword size={12} className="inline mr-2 text-red-600" />}
                         {log.type === 'quest' && <Activity size={12} className="inline mr-2 text-cyan-600" />}
                         {log.type === 'reward' && <Trophy size={12} className="inline mr-2 text-yellow-600" />}
                         {log.type === 'craft' && <Hammer size={12} className="inline mr-2 text-orange-600" />}
                         {log.message}
                      </span>
                   </div>
                ))}

                {isLoadingNarrative && (
                   <div className="flex gap-3 items-center text-pink-400 animate-pulse">
                      <span className="text-slate-600">[{new Date().toLocaleTimeString('en-US', { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" })}]</span>
                      <span className="flex items-center gap-2">
                         <Radio size={12} className="animate-spin" />
                         DECODING_INCOMING_TRANSMISSION...
                      </span>
                   </div>
                )}
                <div ref={logEndRef} />
             </div>

             {activeQuest && (
              <div className="bg-slate-900/80 p-2 border-t border-cyan-500/20">
                <div className="flex justify-between text-[10px] anime-title text-slate-400 mb-1 font-bold px-2">
                  <span className="flex items-center gap-2"><Activity size={12} className="text-pink-500" /> ACTIVE_OP: {activeQuest.quest.title}</span>
                  <span className="text-pink-400 font-mono">{activeQuest.timeRemaining.toFixed(1)}s REMAINING</span>
                </div>
                <div className="h-1 bg-slate-800 w-full overflow-hidden rounded-full mx-2 max-w-[calc(100%-16px)]">
                  <div 
                    className="h-full bg-gradient-to-r from-cyan-500 to-pink-500 shadow-[0_0_10px_#ec4899]" 
                    style={{ width: `${(activeQuest.timeRemaining / activeQuest.quest.duration) * 100}%` }}
                  ></div>
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="max-w-7xl mx-auto">
          {currentScene === 'Character' && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="flex flex-col">
                <div className="flex items-center gap-4 mb-8">
                   <div className="w-2 h-12 bg-cyan-500"></div>
                   <h2 className="anime-title text-4xl text-white font-black tracking-wide">
                     PILOT <span className="text-cyan-400">STATUS</span>
                   </h2>
                </div>

                <div className="aspect-[3/4] max-w-sm mx-auto w-full bg-slate-900/50 border border-slate-700 p-8 relative flex flex-col items-center tech-card-clip">
                  <div className="absolute inset-0 bg-[linear-gradient(rgba(0,243,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,243,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px]"></div>

                  <div className="absolute inset-0 flex items-center justify-center opacity-80 pointer-events-none">
                     <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Kaito&clothing=blazerAndShirt&eyes=surprised&hair=shaggyMullet&hairColor=platinum&skinColor=light" className="w-72 h-72 drop-shadow-[0_0_15px_rgba(0,243,255,0.3)]" alt="Hero" />
                  </div>

                  <div className="relative z-10 w-full h-full grid grid-cols-3 grid-rows-5 gap-4">
                    <div className="col-start-2 row-start-1"><EquipSlot slot="Hat" item={character.equipment.Hat} onUnequip={() => handleUnequip('Hat')} /></div>
                    <div className="col-start-1 row-start-2"><EquipSlot slot="Revolver" item={character.equipment.Revolver} onUnequip={() => handleUnequip('Revolver')} /></div>
                    <div className="col-start-2 row-start-2"><EquipSlot slot="Poncho" item={character.equipment.Poncho} onUnequip={() => handleUnequip('Poncho')} /></div>
                    <div className="col-start-3 row-start-2"><EquipSlot slot="Rifle" item={character.equipment.Rifle} onUnequip={() => handleUnequip('Rifle')} /></div>
                    <div className="col-start-2 row-start-3"><EquipSlot slot="Badge" item={character.equipment.Badge} onUnequip={() => handleUnequip('Badge')} /></div>
                    <div className="col-start-1 row-start-5"><EquipSlot slot="Belt" item={character.equipment.Belt} onUnequip={() => handleUnequip('Belt')} /></div>
                    <div className="col-start-3 row-start-5"><EquipSlot slot="Boots" item={character.equipment.Boots} onUnequip={() => handleUnequip('Boots')} /></div>
                  </div>
                </div>

                <BorderedCard className="mt-10" title="BIO_METRICS">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-8">
                    <StatsBar label="AIM" value={totalStats.aim} max={150} color="from-cyan-500 to-blue-500" tooltip="Targeting system calibration." />
                    <StatsBar label="REFLEX" value={totalStats.reflexes} max={150} color="from-pink-500 to-red-500" tooltip="Neural reaction speed." />
                    <StatsBar label="GRIT" value={totalStats.grit} max={150} color="from-yellow-500 to-orange-500" tooltip="Mental fortitude and shielding." />
                    <StatsBar label="CHARIS" value={totalStats.charisma} max={150} color="from-purple-500 to-indigo-500" tooltip="Social hacking capability." />
                    <StatsBar label="STAM" value={totalStats.stamina} max={150} color="from-green-500 to-emerald-500" tooltip="Energy core capacity." />
                  </div>
                </BorderedCard>
              </div>

              <div className="flex flex-col">
                 <div className="flex items-center gap-4 mb-8">
                   <div className="w-2 h-12 bg-pink-500"></div>
                   <h2 className="anime-title text-4xl text-white font-black tracking-wide">
                     CARGO <span className="text-pink-500">HOLD</span>
                   </h2>
                </div>

                 <BorderedCard className="flex-1" title="STORAGE_UNIT">
                    <div className="grid grid-cols-4 sm:grid-cols-5 gap-3">
                      {character.inventory.map((item, idx) => (
                        <InventorySlot 
                          key={item ? item.id : `empty-${idx}`}
                          item={item} 
                          isSelected={selectedInventoryIdx === idx} 
                          onClick={() => item && setSelectedInventoryIdx(selectedInventoryIdx === idx ? null : idx)} 
                        />
                      ))}
                    </div>

                    {selectedInventoryIdx !== null && character.inventory[selectedInventoryIdx] && (
                      <div className="mt-8 p-6 bg-slate-900 border border-cyan-500/50 shadow-[0_0_20px_rgba(0,243,255,0.1)] relative animate-pop-in">
                        <div className="flex justify-between items-start mb-4">
                          <h4 className="anime-title text-2xl text-cyan-400">{character.inventory[selectedInventoryIdx]!.name}</h4>
                          <span className="bg-pink-900/50 px-3 py-1 text-[10px] anime-title text-pink-300 border border-pink-500">LVL: {character.level}</span>
                        </div>
                        <p className="anime-text text-sm text-slate-300 mb-6 leading-relaxed">
                          {character.inventory[selectedInventoryIdx]!.description}
                        </p>
                        <WesternButton 
                          onClick={() => handleEquip(selectedInventoryIdx!)} 
                          className="w-full text-xl py-4"
                          variant="primary"
                        >
                          EQUIP_GEAR
                        </WesternButton>
                      </div>
                    )}
                 </BorderedCard>
              </div>
            </div>
          )}

          {currentScene === 'Saloon' && (
             <SaloonScene 
                character={character}
                activeQuest={activeQuest}
                startQuest={startQuest}
                addLog={addLog}
                setIsLoadingNarrative={setIsLoadingNarrative}
                isLoadingNarrative={isLoadingNarrative}
             />
          )}

          {currentScene === 'HighNoon' && (
            <ArenaScene 
              character={character}
              onDuel={runDuel}
              isLoading={isLoadingNarrative}
            />
          )}

          {currentScene === 'Gunsmith' && (
             <SynthForgeScene 
                character={character}
                selectedRecipe={selectedRecipe}
                onSelectRecipe={setSelectedRecipe}
                onCraft={handleCraft}
             />
          )}

          {currentScene === 'Sheriff' && (
             <GuildScene 
                currentScene={currentScene}
                onNavigate={setCurrentScene}
             />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateQuestNarrative = async (questTitle: string, characterName: string, species: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Narrate a dramatic anime-style scene of ${characterName}, a ${species} space bounty hunter, completing the mission "${questTitle}". Use a high-energy tone. Mention visual effects like speed lines, glowing auras, energy blasts, or dramatic poses. Max 3 sentences.`,
      config: {
        temperature: 0.8,
      }
    });
    return response.text || "The energy blast clears. The mission is complete.";
  } catch (error) {
    console.warn("Narrative generation failed, using fallback.", error);
    return "The smoke clears. Another victory for the hunter.";
  }
};

export const generateDuelNarrative = async (player: string, playerSpecies: string, opponent: string, opponentSpecies: string, result: 'Win' | 'Loss') => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Describe a high-stakes anime duel between ${player} (a ${playerSpecies}) and ${opponent} (a ${opponentSpecies}). Focus on special moves, power levels, and intense action. ${player} ${result === 'Win' ? 'unleashes a secret technique to win' : 'is overwhelmed by the opponent\'s power level'}. Max 2 sentences.`,
    });
    return response.text || `A flash of light! ${result === 'Win' ? player : opponent} stands victorious amidst the sparks.`;
  } catch (error) {
    console.warn("Duel generation failed, using fallback.", error);
    return `A flash of light! ${result === 'Win' ? player : opponent} stands victorious amidst the sparks.`;
  }
};

import React from 'react';
import { Quest, Character, LogType } from '../../types';
import { QUESTS } from '../../constants';
import { BorderedCard, WesternButton } from '../UI';
import { generateQuestNarrative } from '../../services/geminiService';
import { Compass, Loader2 } from 'lucide-react';

interface SaloonSceneProps {
  character: Character;
  activeQuest: { quest: Quest; timeRemaining: number; startTime: number } | null;
  startQuest: (quest: Quest) => void;
  addLog: (message: string, type: LogType) => void;
  setIsLoadingNarrative: (loading: boolean) => void;
  isLoadingNarrative: boolean;
}

export const SaloonScene: React.FC<SaloonSceneProps> = ({
  character,
  activeQuest,
  startQuest,
  addLog,
  setIsLoadingNarrative,
  isLoadingNarrative
}) => {

  const handleExpedition = async () => {
    if (isLoadingNarrative) return;

    setIsLoadingNarrative(true);
    addLog("Initializing expedition protocols... Scouting wild sectors...", 'system');

    const randomQuest = QUESTS[Math.floor(Math.random() * QUESTS.length)];

    try {
        const timeoutPromise = new Promise<string>((_, reject) => 
            setTimeout(() => reject(new Error("Expedition timeout")), 10000)
        );

        const narrative = await Promise.race([
            generateQuestNarrative(randomQuest.title, character.name, character.species),
            timeoutPromise
        ]);

        addLog(`Expedition Report: ${narrative}`, 'quest');
    } catch (e) {
        addLog("Expedition failed: Signal interference detected. Please retry.", 'system');
    } finally {
        setIsLoadingNarrative(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
       <h2 className="anime-title text-6xl mb-12 text-white text-center drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]">
         <span className="text-cyan-500">NEO</span>_HUB
       </h2>
       <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          <BorderedCard title="MISSION_BOARD">
            <div className="space-y-4">
              {QUESTS.map(q => (
                <div key={q.id} className="p-4 bg-slate-800/50 border border-slate-600 flex justify-between items-center group hover:border-cyan-400 transition-all cursor-pointer relative overflow-hidden">
                  <div className="absolute inset-0 bg-cyan-500/5 translate-x-[-100%] group-hover:translate-x-0 transition-transform"></div>
                  <div className="relative z-10">
                    <h4 className="anime-title text-lg text-white group-hover:text-cyan-300">{q.title}</h4>
                    <div className="text-[10px] anime-title text-slate-400 mt-2 flex items-center gap-2">
                      <span className="bg-slate-900 px-2 border border-slate-700 text-pink-400">{q.difficulty}</span>
                      <span className="text-cyan-600">REWARD: {q.reward.gold}¥ | {q.reward.exp}XP</span>
                    </div>
                  </div>
                  <WesternButton 
                    variant="secondary" 
                    disabled={!!activeQuest}
                    onClick={() => startQuest(q)}
                    className="py-1 px-4 text-xs z-10"
                  >
                    ACCEPT
                  </WesternButton>
                </div>
              ))}
            </div>
          </BorderedCard>
          <div className="space-y-8">
            <div className="aspect-video bg-black border border-slate-700 relative overflow-hidden group rounded-lg">
               <img src="https://images.unsplash.com/photo-1534234828563-025317354318?auto=format&fit=crop&q=80&w=800" className="w-full h-full object-cover opacity-60 hover:scale-110 transition-all duration-700" alt="Cyberpunk City" />
               <div className="absolute inset-0 bg-gradient-to-t from-slate-900 to-transparent"></div>
               <div className="absolute bottom-4 left-4 flex items-center gap-3">
                  <div className="w-2 h-2 bg-pink-500 rounded-full animate-ping"></div>
                  <span className="anime-title text-2xl text-white drop-shadow-lg">SECTOR_7</span>
               </div>
            </div>

            <BorderedCard title="FREE_ROAM">
               <div className="flex flex-col gap-4">
                 <p className="anime-text text-sm text-slate-400">
                   Venture into the unknown. Generate a random narrative event based on your character.
                 </p>
                 <WesternButton 
                    variant="accent"
                    onClick={handleExpedition}
                    disabled={isLoadingNarrative}
                    className={`w-full py-4 flex justify-center items-center shadow-[0_0_15px_rgba(168,85,247,0.3)] hover:shadow-[0_0_25px_rgba(168,85,247,0.5)] transition-shadow`}
                 >
                    {isLoadingNarrative ? (
                        <>
                            <Loader2 size={20} className="mr-2 animate-spin" />
                            SCOUTING...
                        </>
                    ) : (
                        <>
                            <Compass size={20} className="mr-2" />
                            EMBARK EXPEDITION
                        </>
                    )}
                 </WesternButton>
               </div>
            </BorderedCard>

            <BorderedCard title="GLOBAL_CHAT">
               <p className="anime-text text-xs text-green-400 leading-relaxed font-mono">
                 > User_99: Anyone seen the Void Dragon yet?<br/>
                 > Admin: Bounty updated for Sector 4.<br/>
                 > Kaito: LFG Daily Raid.
               </p>
            </BorderedCard>
          </div>
       </div>
    </div>
  );
};

import React from 'react';
import { Character, Recipe } from '../../types';
import { RECIPES } from '../../constants';
import { WesternButton, BorderedCard } from '../UI';
import { Hammer, Cpu, Package, ArrowRight } from 'lucide-react';

interface SynthForgeSceneProps {
  character: Character;
  selectedRecipe: Recipe | null;
  onSelectRecipe: (recipe: Recipe) => void;
  onCraft: () => void;
}

export const SynthForgeScene: React.FC<SynthForgeSceneProps> = ({ 
  character, 
  selectedRecipe, 
  onSelectRecipe, 
  onCraft 
}) => {
  return (
     <div className="max-w-6xl mx-auto h-[700px] flex gap-8">
       {/* Recipe List */}
       <div className="w-1/3 flex flex-col gap-4 overflow-y-auto pr-2 custom-scrollbar h-full">
          <h2 className="anime-title text-3xl text-orange-500 mb-4 flex items-center gap-3">
             <Hammer /> BLUEPRINTS
          </h2>
          {RECIPES.map(recipe => (
             <button 
                key={recipe.id}
                onClick={() => onSelectRecipe(recipe)}
                className={`p-4 border-l-4 cursor-pointer transition-all text-left w-full group ${
                   selectedRecipe?.id === recipe.id 
                   ? 'bg-orange-900/20 border-orange-500 text-orange-200 shadow-[0_0_15px_rgba(249,115,22,0.2)]' 
                   : 'bg-slate-900/50 border-slate-700 text-slate-400 hover:bg-slate-800'
                }`}
             >
                <div className="flex justify-between items-center">
                    <h4 className="anime-title font-bold text-lg group-hover:text-orange-300 transition-colors">{recipe.name}</h4>
                    {selectedRecipe?.id === recipe.id && <ArrowRight size={16} className="text-orange-500" />}
                </div>
                <div className="flex gap-2 mt-2">
                   <span className={`text-[10px] px-2 py-0.5 rounded border ${
                      recipe.result.rarity === 'Epic' ? 'border-purple-500 text-purple-400' :
                      recipe.result.rarity === 'Rare' ? 'border-cyan-500 text-cyan-400' : 
                      'border-slate-500 text-slate-400'
                   }`}>
                      {recipe.result.rarity}
                   </span>
                   <span className="text-[10px] px-2 py-0.5 rounded border border-slate-600 text-slate-400">
                      {recipe.result.slot}
                   </span>
                </div>
             </button>
          ))}
       </div>

       {/* Crafting Area */}
       <div className="flex-1 bg-slate-900/80 border border-orange-500/30 relative overflow-hidden flex flex-col tech-card-clip">
          <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none">
             <Cpu size={200} className="text-orange-500" />
          </div>

          {selectedRecipe ? (
             <div className="p-8 relative z-10 flex flex-col h-full">
                <div className="flex justify-between items-start mb-8">
                   <div>
                      <h3 className="anime-title text-4xl text-orange-400 mb-2 drop-shadow-md">{selectedRecipe.result.name}</h3>
                      <p className="anime-text text-slate-400 italic">"{selectedRecipe.result.description}"</p>
                   </div>
                   <div className="w-16 h-16 border border-orange-500 bg-black/50 flex items-center justify-center shadow-[0_0_15px_rgba(249,115,22,0.3)]">
                      <Package size={32} className="text-orange-500" />
                   </div>
                </div>

                <div className="grid grid-cols-2 gap-8 mb-8">
                   <BorderedCard title="OUTPUT_SPECS" className="bg-black/40">
                      <div className="space-y-2 mt-2">
                         {Object.keys(selectedRecipe.result.stats).length > 0 ? Object.entries(selectedRecipe.result.stats).map(([stat, val]) => (
                            <div key={stat} className="flex justify-between items-center text-sm">
                               <span className="anime-title text-slate-500 uppercase">{stat}</span>
                               <span className="anime-title text-orange-300">+{val}</span>
                            </div>
                         )) : <span className="text-slate-600 text-xs italic">No stat modifiers.</span>}
                      </div>
                   </BorderedCard>

                   <BorderedCard title="REQUIRED_MATS" className="bg-black/40">
                      <div className="space-y-3 mt-2">
                         {selectedRecipe.ingredients.map((ing, idx) => {
                            const ownedCount = character.inventory.filter(i => i?.id === ing.itemId).length;
                            const hasEnough = ownedCount >= ing.count;
                            return (
                               <div key={idx} className="flex justify-between items-center">
                                  <span className="anime-text text-sm text-slate-300">{ing.name}</span>
                                  <span className={`anime-title text-sm ${hasEnough ? 'text-green-400' : 'text-red-400'}`}>
                                     {ownedCount} / {ing.count}
                                  </span>
                               </div>
                            );
                         })}
                      </div>
                   </BorderedCard>
                </div>

                <div className="mt-auto flex justify-center">
                   <WesternButton 
                      variant="secondary" 
                      className="w-full max-w-md py-6 text-2xl border-orange-500 text-orange-100 bg-orange-900/50 hover:bg-orange-800 shadow-[0_0_20px_rgba(249,115,22,0.2)]"
                      onClick={onCraft}
                   >
                      <Hammer className="mr-2 inline" /> INITIATE_SYNTHESIS
                   </WesternButton>
                </div>
             </div>
          ) : (
             <div className="h-full flex flex-col items-center justify-center text-slate-600">
                <Hammer size={64} className="mb-4 opacity-50 animate-bounce" />
                <span className="anime-title text-xl">SELECT_BLUEPRINT</span>
             </div>
          )}
       </div>
     </div>
  );
};
